#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=15;
int n,dp[N][N][N][N][N],a,b,c,d,e,ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a>>b>>c>>d>>e;
		for(int j=1;j<=9;j++)
		{
			dp[(a+j)%10][b][c][d][e]++;
			dp[a][(b+j)%10][c][d][e]++;
			dp[a][b][(c+j)%10][d][e]++;
			dp[a][b][c][(d+j)%10][e]++;
			dp[a][b][c][d][(e+j)%10]++;
			dp[(a+j)%10][(b+j)%10][c][d][e]++;
			dp[a][(b+j)%10][(c+j)%10][d][e]++;
			dp[a][b][(c+j)%10][(d+j)%10][e]++;
			dp[a][b][c][(d+j)%10][(e+j)%10]++;
		}
	}
	for(int aa=0;aa<=9;aa++)
	{
		for(int bb=0;bb<=9;bb++)
		{
			for(int cc=0;cc<=9;cc++)
			{
				for(int dd=0;dd<=9;dd++)
				{
					for(int ee=0;ee<=9;ee++)
					{
						if(dp[aa][bb][cc][dd][ee]==n) ans++;
					}
				}
			}
		}
	}
	cout<<ans;
	return 0;
}
